import java.io.*;

public class SecureCommandExecutionDemo {
    public static void main(String[] args) {
        try {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a command to execute: ");
            String userInput = br.readLine();

            // Sanitize user input to prevent command injection
            String sanitizedInput = userInput.replaceAll("[^a-zA-Z0-9.-]", "");

            // Only allow alphanumeric characters, dots, and dashes in the command
            ProcessBuilder processBuilder = new ProcessBuilder("ping", "-c", "4", sanitizedInput);
            Process process = processBuilder.start();

            BufferedReader inputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = inputReader.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

